81: // NewForConfig creates a new dynamic client or returns an error.
82: // NewForConfig is equivalent to NewForConfigAndClient(c, httpClient),
83: // where httpClient was generated with rest.HTTPClientFor(c).
84: func NewForConfig(inConfig *rest.Config) (*DynamicClient, error) {
85: 	config := ConfigFor(inConfig)
86: 
87: 	httpClient, err := rest.HTTPClientFor(config)
88: 	if err != nil {
89: 		return nil, err
90: 	}
91: 	return NewForConfigAndClient(config, httpClient)
92: }
