94: // NewForConfigAndClient creates a new dynamic client for the given config and http client.
95: // Note the http client provided takes precedence over the configured transport values.
96: func NewForConfigAndClient(inConfig *rest.Config, h *http.Client) (*DynamicClient, error) {
97: 	config := ConfigFor(inConfig)
98: 	config.GroupVersion = nil
99: 	config.APIPath = "/if-you-see-this-search-for-the-break"
100: 
101: 	restClient, err := rest.UnversionedRESTClientForConfigAndClient(config, h)
102: 	if err != nil {
103: 		return nil, err
104: 	}
105: 	return &DynamicClient{client: restClient}, nil
106: }
