387: func (c *dynamicResourceClient) makeURLSegments(name string) []string {
388: 	url := []string{}
389: 	if len(c.resource.Group) == 0 {
390: 		url = append(url, "api")
391: 	} else {
392: 		url = append(url, "apis", c.resource.Group)
393: 	}
394: 	url = append(url, c.resource.Version)
395: 
396: 	if len(c.namespace) > 0 {
397: 		url = append(url, "namespaces", c.namespace)
398: 	}
399: 	url = append(url, c.resource.Resource)
400: 
401: 	if len(name) > 0 {
402: 		url = append(url, name)
403: 	}
404: 
405: 	return url
406: }
